     1→/**
     2→ * MMS TypeScript Fallback Optimizer
     3→ *
     4→ * Greedy algorithm implementation for train-to-route assignment.
     5→ * Used as fallback when C++ OR-Tools optimizer is unavailable,
     6→ * times out, or returns INFEASIBLE.
     7→ *
     8→ * Algorithm:
     9→ * 1. Sort routes by required trains (descending) - prioritize high-demand routes
    10→ * 2. Sort trains by mileage balance (ascending) - prioritize under-utilized trains
    11→ * 3. For each route, greedily assign compatible fit trains
    12→ * 4. Generate explanation traces for each assignment
    13→ *
    14→ * @see specs/002-architecture.md Section 2.4
    15→ * @see specs/004-domain-services.md Section 4.3.2
    16→ */
    17→
    18→import { logger } from '../lib/logging/logger';
    19→import { withSpan } from '../lib/tracing';
    20→import {
    21→  type OptimizerFullInput,
    22→  type OptimizerFullResult,
    23→  type Assignment,
    24→  type UnassignedTrain,
    25→  type MaterialWarning,
    26→  type ExplanationTrace,
    27→  type OptimizerTrainInput,
    28→  type OptimizerRouteInput,
    29→  type ResultSummary,
    30→} from './types';
    31→
    32→// =============================================================================
    33→// Fallback Optimizer
    34→// =============================================================================
    35→
    36→/**
    37→ * TypeScript greedy fallback optimizer
    38→ *
    39→ * Provides a reasonable solution when the C++ optimizer is unavailable.
    40→ * Prioritizes mileage balancing while respecting all hard constraints.
    41→ */
    42→export class FallbackOptimizer {
    43→  private readonly log = logger.child({ service: 'FallbackOptimizer' });
    44→
    45→  /**
    46→   * Run the greedy optimization algorithm
    47→   */
    48→  async optimize(input: OptimizerFullInput): Promise<OptimizerFullResult> {
    49→    return withSpan('optimizer.fallback.optimize', async (span) => {
    50→      const startTime = Date.now();
    51→
    52→      span.setAttribute('requestId', input.requestId);
    53→      span.setAttribute('trainCount', input.trains.length);
    54→      span.setAttribute('routeCount', input.routes.length);
    55→      span.setAttribute('hardConstraintCount', input.hardConstraints.length);
    56→      span.setAttribute('softConstraintCount', input.softConstraints.length);
    57→
    58→      this.log.info(
    59→        {
    60→          requestId: input.requestId,
    61→          trainCount: input.trains.length,
    62→          routeCount: input.routes.length,
    63→        },
    64→        'Starting fallback optimization'
    65→      );
    66→
    67→      const assignments: Assignment[] = [];
    68→      const unassigned: UnassignedTrain[] = [];
    69→      const materialWarnings: MaterialWarning[] = [];
    70→      const assignedTrainIds = new Set<string>();
    71→      const softConstraintBreakdown: Record<string, number> = {};
    72→
    73→      // Build lookup maps for efficiency
    74→      const unavailableTrainIds = this.getUnavailableTrainIds(input);
    75→      const trainConstraintMap = this.buildTrainConstraintMap(input);
    76→      const routeCompatibilityMap = this.buildRouteCompatibilityMap(input);
    77→
    78→      // Sort routes by required trains (descending) - prioritize high-demand routes
    79→      const sortedRoutes = [...input.routes].sort(
    80→        (a, b) => b.requiredTrains - a.requiredTrains
    81→      );
    82→
    83→      // Sort trains by mileage balance - prioritize under-utilized trains
    84→      const sortedTrains = this.getSortedTrains(input.trains);
    85→
    86→      // Check material warnings for pending PMs
    87→      materialWarnings.push(...this.checkMaterialWarnings(input));
    88→
    89→      // Greedy assignment
    90→      for (const route of sortedRoutes) {
    91→        let assignedCount = 0;
    92→
    93→        for (const train of sortedTrains) {
    94→          if (assignedCount >= route.requiredTrains) break;
    95→          if (assignedTrainIds.has(train.id)) continue;
    96→
    97→          // Check hard constraints
    98→          const blockingReason = this.checkHardConstraints(
    99→            train,
   100→            route,
   101→            input,
   102→            unavailableTrainIds,
   103→            trainConstraintMap,
   104→            routeCompatibilityMap
   105→          );
   106→
   107→          if (blockingReason) {
   108→            continue;
   109→          }
   110→
   111→          // Check fleet compatibility
   112→          if (
   113→            route.allowedFleetIds.length > 0 &&
   114→            !route.allowedFleetIds.includes(train.fleetId)
   115→          ) {
   116→            continue;
   117→          }
   118→
   119→          // Assign train to route
   120→          const explanation = this.generateExplanation(train, route, input);
   121→          const score = this.calculateScore(train, route, input, explanation);
   122→
   123→          // Track soft constraint penalties
   124→          for (const exp of explanation) {
   125→            if (exp.constraintType === 'SOFT') {
   126→              const key = exp.constraintName;
   127→              softConstraintBreakdown[key] =
   128→                (softConstraintBreakdown[key] || 0) + Math.abs(exp.impact);
   129→            }
   130→          }
   131→
   132→          assignments.push({
   133→            trainId: train.id,
   134→            routeId: route.id,
   135→            score,
   136→            explanation,
   137→          });
   138→
   139→          assignedTrainIds.add(train.id);
   140→          assignedCount++;
   141→        }
   142→
   143→        // Record route shortfall
   144→        if (assignedCount < route.requiredTrains) {
   145→          unassigned.push({
   146→            routeId: route.id,
   147→            shortfall: route.requiredTrains - assignedCount,
   148→            reason: 'Insufficient fit trains available for route requirements',
   149→            blockingConstraints: [`Required: ${route.requiredTrains}, Assigned: ${assignedCount}`],
   150→          });
   151→        }
   152→      }
   153→
   154→      // Record unassigned trains with reasons
   155→      for (const train of input.trains) {
   156→        if (assignedTrainIds.has(train.id)) continue;
   157→
   158→        const reason = this.findBlockingReason(
   159→          train,
   160→          input,
   161→          unavailableTrainIds,
   162→          trainConstraintMap
   163→        );
   164→
   165→        unassigned.push({
   166→          trainId: train.id,
   167→          reason,
   168→          blockingConstraints: this.getBlockingConstraints(train, input, trainConstraintMap),
   169→        });
   170→      }
   171→
   172→      // Validate service demand
   173→      this.validateServiceDemand(input, assignments, unassigned);
   174→
   175→      const solveTimeMs = Date.now() - startTime;
   176→
   177→      const summary: ResultSummary = {
   178→        totalPenalty: this.calculateTotalPenalty(assignments),
   179→        trainsAssigned: assignments.length,
   180→        trainsUnassigned: input.trains.length - assignments.length,
   181→        softConstraintBreakdown,
   182→        materialBlocks: materialWarnings.filter(
   183→          (w) => w.status === 'UNAVAILABLE'
   184→        ).length,
   185→      };
   186→
   187→      span.setAttribute('status', 'FALLBACK');
   188→      span.setAttribute('trainsAssigned', summary.trainsAssigned);
   189→      span.setAttribute('trainsUnassigned', summary.trainsUnassigned);
   190→      span.setAttribute('solveTimeMs', solveTimeMs);
   191→
   192→      this.log.info(
   193→        {
   194→          requestId: input.requestId,
   195→          status: 'FALLBACK',
   196→          trainsAssigned: summary.trainsAssigned,
   197→          trainsUnassigned: summary.trainsUnassigned,
   198→          solveTimeMs,
   199→        },
   200→        'Fallback optimization complete'
   201→      );
   202→
   203→      return {
   204→        type: 'RESULT',
   205→        requestId: input.requestId,
   206→        status: 'FALLBACK',
   207→        solveTimeMs,
   208→        assignments,
   209→        unassigned,
   210→        materialWarnings,
   211→        summary,
   212→      };
   213→    });
   214→  }
   215→
   216→  /**
   217→   * Get sorted trains by mileage balance (under-utilized first)
   218→   */
   219→  private getSortedTrains(trains: OptimizerTrainInput[]): OptimizerTrainInput[] {
   220→    return [...trains]
   221→      .filter((t) => t.fitnessStatus === 'FIT')
   222→      .sort((a, b) => {
   223→        // Prioritize under-utilized trains (lower current mileage vs target)
   224→        const aBalance = a.currentMileageKm - a.targetMileageKm;
   225→        const bBalance = b.currentMileageKm - b.targetMileageKm;
   226→        return aBalance - bBalance;
   227→      });
   228→  }
   229→
   230→  /**
   231→   * Get set of unavailable train IDs from events
   232→   */
   233→  private getUnavailableTrainIds(input: OptimizerFullInput): Set<string> {
   234→    const unavailable = new Set<string>();
   235→
   236→    if (input.unavailabilityEvents) {
   237→      for (const event of input.unavailabilityEvents) {
   238→        if (event.status === 'ACTIVE' && event.blocksRunAssignment) {
   239→          unavailable.add(event.trainId);
   240→        }
   241→      }
   242→    }
   243→
   244→    return unavailable;
   245→  }
   246→
   247→  /**
   248→   * Build map of train ID to hard constraints
   249→   */
   250→  private buildTrainConstraintMap(
   251→    input: OptimizerFullInput
   252→  ): Map<string, string[]> {
   253→    const map = new Map<string, string[]>();
   254→
   255→    for (const constraint of input.hardConstraints) {
   256→      const existing = map.get(constraint.trainId) || [];
   257→      existing.push(constraint.description);
   258→      map.set(constraint.trainId, existing);
   259→    }
   260→
   261→    return map;
   262→  }
   263→
   264→  /**
   265→   * Build map of train+route to compatibility info
   266→   */
   267→  private buildRouteCompatibilityMap(
   268→    input: OptimizerFullInput
   269→  ): Map<string, boolean> {
   270→    const map = new Map<string, boolean>();
   271→
   272→    if (input.routeCompatibility) {
   273→      for (const compat of input.routeCompatibility) {
   274→        if (compat.trainId) {
   275→          const key = `${compat.trainId}:${compat.routeId}`;
   276→          map.set(key, compat.isCompatible);
   277→        }
   278→      }
   279→    }
   280→
   281→    return map;
   282→  }
   283→
   284→  /**
   285→   * Check hard constraints for a train-route pair
   286→   * Returns blocking reason or null if valid
   287→   */
   288→  private checkHardConstraints(
   289→    train: OptimizerTrainInput,
   290→    route: OptimizerRouteInput,
   291→    input: OptimizerFullInput,
   292→    unavailableTrainIds: Set<string>,
   293→    trainConstraintMap: Map<string, string[]>,
   294→    routeCompatibilityMap: Map<string, boolean>
   295→  ): string | null {
   296→    // Check fitness status
   297→    if (train.fitnessStatus !== 'FIT') {
   298→      return `Train is ${train.fitnessStatus}`;
   299→    }
   300→
   301→    // Check unavailability events
   302→    if (unavailableTrainIds.has(train.id)) {
   303→      const event = input.unavailabilityEvents?.find(
   304→        (e) => e.trainId === train.id && e.status === 'ACTIVE'
   305→      );
   306→      return `Train unavailable: ${event?.eventType || 'Unknown'} - ${
   307→        event?.description || event?.externalReference || 'No details'
   308→      }`;
   309→    }
   310→
   311→    // Check explicit hard constraints
   312→    const constraints = trainConstraintMap.get(train.id);
   313→    if (constraints && constraints.length > 0) {
   314→      return constraints[0];
   315→    }
   316→
   317→    // Check route compatibility
   318→    const compatKey = `${train.id}:${route.id}`;
   319→    if (routeCompatibilityMap.has(compatKey) && !routeCompatibilityMap.get(compatKey)) {
   320→      const compat = input.routeCompatibility?.find(
   321→        (c) => c.trainId === train.id && c.routeId === route.id
   322→      );
   323→      return `Route incompatible: ${compat?.constraintType || 'Technical'} - ${
   324→        compat?.restrictionReason || 'Restriction'
   325→      }`;
   326→    }
   327→
   328→    // Check pending PMs due today that block assignment
   329→    const today = input.assignmentDate;
   330→    if (input.pendingPms) {
   331→      for (const pm of input.pendingPms) {
   332→        if (pm.trainId === train.id && pm.targetDate <= today) {
   333→          // Check if blocking materials are unavailable
   334→          const hasBlockingMaterial = pm.requiredMaterials.some((mat) => {
   335→            if (mat.criticality !== 'BLOCKING') return false;
   336→
   337→            const position = input.materialPositions?.find(
   338→              (p) =>
   339→                p.partNumber === mat.partNumber &&
   340→                p.depotId === train.homeDepotId
   341→            );
   342→
   343→            return !position || position.quantityAvailable < mat.quantity;
   344→          });
   345→
   346→          if (!hasBlockingMaterial) {
   347→            return `PM ${pm.pmType} due today - train needs maintenance`;
   348→          }
   349→        }
   350→      }
   351→    }
   352→
   353→    return null;
   354→  }
   355→
   356→  /**
   357→   * Generate explanation traces for an assignment
   358→   */
   359→  private generateExplanation(
   360→    train: OptimizerTrainInput,
   361→    route: OptimizerRouteInput,
   362→    input: OptimizerFullInput
   363→  ): ExplanationTrace[] {
   364→    const explanation: ExplanationTrace[] = [];
   365→    const verbosity = input.config.explanationVerbosity;
   366→
   367→    // Mileage balance explanation
   368→    const mileageBalance = train.currentMileageKm - train.targetMileageKm;
   369→    const mileageImpact =
   370→      (Math.abs(mileageBalance) / 1000) *
   371→      input.config.softConstraintPenalties.mileageImbalance;
   372→
   373→    explanation.push({
   374→      constraintType: 'SOFT',
   375→      constraintName: 'MILEAGE_BALANCE',
   376→      impact: mileageBalance < 0 ? -mileageImpact : mileageImpact,
   377→      description: `Train is ${Math.abs(mileageBalance).toLocaleString()}km ${
   378→        mileageBalance < 0 ? 'under' : 'over'
   379→      } target mileage`,
   380→    });
   381→
   382→    // Depot preference explanation
   383→    if (train.homeDepotId !== train.currentDepotId) {
   384→      const depotImpact = input.config.softConstraintPenalties.preferenceViolation;
   385→      explanation.push({
   386→        constraintType: 'SOFT',
   387→        constraintName: 'DEPOT_PREFERENCE',
   388→        impact: depotImpact,
   389→        description: `Train is away from home depot`,
   390→      });
   391→    }
   392→
   393→    // Route expected km explanation (detailed mode)
   394→    if (verbosity === 'DETAILED') {
   395→      explanation.push({
   396→        constraintType: 'SOFT',
   397→        constraintName: 'ROUTE_UTILIZATION',
   398→        impact: 0,
   399→        description: `Route ${route.routeCode} expected to add ${route.expectedKmPerDay}km`,
   400→      });
   401→    }
   402→
   403→    // Soft constraint penalties from input
   404→    for (const constraint of input.softConstraints) {
   405→      if (constraint.trainId === train.id) {
   406→        explanation.push({
   407→          constraintType: 'SOFT',
   408→          constraintName: constraint.type,
   409→          impact: constraint.penaltyWeight,
   410→          description: constraint.description,
   411→        });
   412→      }
   413→    }
