/**
 * Optimizer Routes
 *
 * REST endpoints for triggering and monitoring optimization jobs.
 * Jobs are processed asynchronously via BullMQ workers.
 *
 * Endpoints:
 * - POST /optimizer/run-assignment - Trigger train-to-route assignment optimization
 * - GET /optimizer/jobs/:jobId - Get job status and results
 * - POST /optimizer/tactical-schedule - Trigger tactical PM scheduling (12-week)
 * - POST /optimizer/strategic-plan - Trigger strategic planning (10-year)
 *
 * @see specs/005-api.md Section 5.6
 */

import { Hono } from 'hono';
import {
  success,
  error,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import { isValidUuid } from '../../lib/schemas';
import {
  addJob,
  getQueue,
  QUEUE_NAMES,
  type OptimizerJobData,
  type TacticalSchedulerJobData,
  type StrategicPlannerJobData,
} from '../../lib/queue';

export const optimizerRoutes = new Hono<{ Variables: AppVariables }>();

// =============================================================================
// Types
// =============================================================================

/**
 * Request body for POST /optimizer/run-assignment
 */
interface RunAssignmentRequest {
  date: string; // ISO date string (YYYY-MM-DD)
  fleetId: string;
  depotId?: string;
  options?: {
    maxSolveTimeSeconds?: number;
    explanationVerbosity?: 'MINIMAL' | 'STANDARD' | 'DETAILED';
  };
  constraints?: {
    serviceRequirements?: Record<string, number>;
    unavailableTrains?: string[];
    preferredAssignments?: Record<string, string>;
  };
}

/**
 * Request body for POST /optimizer/tactical-schedule
 */
interface TacticalScheduleRequest {
  depotId?: string;
  fleetId?: string;
  trainIds?: string[];
  horizonWeeks?: number; // Default 12
  dryRun?: boolean;
}

/**
 * Request body for POST /optimizer/strategic-plan
 */
interface StrategicPlanRequest {
  horizonYears?: number; // Default 10
  fromBaselineId?: string;
  fleetId?: string;
  populationSize?: number;
  generations?: number;
}

/**
 * Optimizer job status response
 */
type OptimizerJobStatus =
  | 'waiting'
  | 'active'
  | 'completed'
  | 'failed'
  | 'delayed'
  | 'unknown';

// =============================================================================
// Helper Functions
// =============================================================================

/**
 * Validate ISO date string (YYYY-MM-DD)
 */
function isValidDateString(date: string): boolean {
  if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
    return false;
  }
  const parsed = new Date(date);
  return !isNaN(parsed.getTime());
}

/**
 * Get detailed job information including result
 */
async function getDetailedJob(
  queueName: typeof QUEUE_NAMES[keyof typeof QUEUE_NAMES],
  jobId: string
): Promise<{
  id: string;
  status: OptimizerJobStatus;
  progress?: unknown;
  result?: unknown;
  failedReason?: string;
  startedAt?: string;
  completedAt?: string;
  attemptsMade?: number;
} | null> {
  const queue = getQueue(queueName);
  const job = await queue.getJob(jobId);

  if (!job) return null;

  const state = await job.getState();
  const result = job.returnvalue;
  const failedReason = job.failedReason;
  const progress = job.progress;
  const processedOn = job.processedOn;
  const finishedOn = job.finishedOn;

  return {
    id: job.id!,
    status: (state as OptimizerJobStatus) || 'unknown',
    ...(progress !== undefined && { progress }),
    ...(result !== undefined && { result }),
    ...(failedReason && { failedReason }),
    ...(processedOn && { startedAt: new Date(processedOn).toISOString() }),
    ...(finishedOn && { completedAt: new Date(finishedOn).toISOString() }),
    attemptsMade: job.attemptsMade,
  };
}

/**
 * Estimate completion time based on job complexity
 */
function estimateCompletionSeconds(trainCount: number, routeCount: number): number {
  // Rough estimate: base time + scaling factor
  const baseTime = 10;
  const scaleFactor = 0.5;
  return Math.ceil(baseTime + (trainCount * routeCount * scaleFactor) / 1000);
}

// =============================================================================
// Routes
// =============================================================================

/**
 * POST /optimizer/run-assignment
 *
 * Trigger run assignment optimization for a specific date and fleet.
 * The optimization is performed asynchronously and returns a job ID
 * that can be used to check status and retrieve results.
 */
optimizerRoutes.post('/optimizer/run-assignment', async (c) => {
  const requestId = getRequestId(c);

  // Parse request body
  let body: RunAssignmentRequest;
  try {
    body = await c.req.json();
  } catch {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON body', requestId),
      400
    );
  }

  // Validate required fields
  if (!body.date) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'date is required', requestId, {
        field: 'date',
      }),
      400
    );
  }

  if (!isValidDateString(body.date)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        'Invalid date format. Expected YYYY-MM-DD',
        requestId,
        { field: 'date', value: body.date }
      ),
      400
    );
  }

  if (!body.fleetId) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'fleetId is required', requestId, {
        field: 'fleetId',
      }),
      400
    );
  }

  if (!isValidUuid(body.fleetId)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        'Invalid fleetId format. Expected UUID',
        requestId,
        { field: 'fleetId', value: body.fleetId }
      ),
      400
    );
  }

  // Validate options if provided
  const maxSolveTimeSeconds = body.options?.maxSolveTimeSeconds ?? 30;
  if (maxSolveTimeSeconds < 1 || maxSolveTimeSeconds > 300) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        'maxSolveTimeSeconds must be between 1 and 300',
        requestId,
        { field: 'options.maxSolveTimeSeconds', value: maxSolveTimeSeconds }
      ),
      400
    );
  }

  const validVerbosityLevels = ['MINIMAL', 'STANDARD', 'DETAILED'];
  const verbosity = body.options?.explanationVerbosity ?? 'STANDARD';
  if (!validVerbosityLevels.includes(verbosity)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        `explanationVerbosity must be one of: ${validVerbosityLevels.join(', ')}`,
        requestId,
        { field: 'options.explanationVerbosity', value: verbosity }
      ),
      400
    );
  }

  // Build job data
  const jobData: OptimizerJobData = {
    date: body.date,
    fleetId: body.fleetId,
    timeoutMs: maxSolveTimeSeconds * 1000,
    ...(body.constraints && { constraints: body.constraints }),
  };

  // Add job to queue
  const { id: jobId } = await addJob(
    QUEUE_NAMES.OPTIMIZER,
    'run-assignment',
    jobData,
    {
      priority: 1, // High priority for run assignments
    }
  );

  // Estimate completion time (this would be more accurate with fleet size info)
  const estimatedCompletionSeconds = estimateCompletionSeconds(50, 10);

  return c.json(
    success(
      {
        jobId,
        status: 'QUEUED',
        estimatedCompletionSeconds,
      },
      {
        timing: { durationMs: getRequestDuration(c) },
      }
    ),
    202
  );
});

/**
 * GET /optimizer/jobs/:jobId
 *
 * Get the status and results of an optimizer job.
 */
optimizerRoutes.get('/optimizer/jobs/:jobId', async (c) => {
  const requestId = getRequestId(c);
  const jobId = c.req.param('jobId');

  // Try to find job in optimizer queue first
  let job = await getDetailedJob(QUEUE_NAMES.OPTIMIZER, jobId);

  // If not found, try tactical scheduler queue
  if (!job) {
    job = await getDetailedJob(QUEUE_NAMES.TACTICAL_SCHEDULER, jobId);
  }

  // If not found, try strategic planner queue
  if (!job) {
    job = await getDetailedJob(QUEUE_NAMES.STRATEGIC_PLANNER, jobId);
  }

  if (!job) {
    return c.json(
      error(ErrorCodes.NOT_FOUND, `Job ${jobId} not found`, requestId),
      404
    );
  }

  // Map internal status to API status
  const statusMap: Record<string, string> = {
    waiting: 'QUEUED',
    delayed: 'QUEUED',
    active: 'PROCESSING',
    completed: 'COMPLETED',
    failed: 'FAILED',
  };

  const apiStatus = statusMap[job.status] || 'UNKNOWN';

  // Build response based on job status
  interface JobResponse {
    jobId: string;
    status: string;
    startedAt?: string;
    completedAt?: string;
    progress?: unknown;
    result?: unknown;
    error?: {
      message: string;
      attemptsMade?: number;
    };
  }

  const response: JobResponse = {
    jobId: job.id,
    status: apiStatus,
    ...(job.startedAt && { startedAt: job.startedAt }),
    ...(job.completedAt && { completedAt: job.completedAt }),
  };

  // Include progress for active jobs
  if (job.status === 'active' && job.progress) {
    response.progress = job.progress;
  }

  // Include result for completed jobs
  if (job.status === 'completed' && job.result) {
    response.result = job.result;
  }

  // Include error for failed jobs
  if (job.status === 'failed' && job.failedReason) {
    response.error = {
      message: job.failedReason,
      attemptsMade: job.attemptsMade,
    };
  }

  return c.json(
    success(response, {
      timing: { durationMs: getRequestDuration(c) },
    })
  );
});

/**
 * POST /optimizer/tactical-schedule
 *
 * Trigger tactical PM scheduling for a 12-week horizon.
 * Optimizes PM placement considering track availability,
 * material constraints, and man-hour capacity.
 */
optimizerRoutes.post('/optimizer/tactical-schedule', async (c) => {
  const requestId = getRequestId(c);

  // Parse request body
  let body: TacticalScheduleRequest;
  try {
    body = await c.req.json();
  } catch {
    body = {}; // Allow empty body for default parameters
  }

  // Validate depotId if provided
  if (body.depotId && !isValidUuid(body.depotId)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        'Invalid depotId format. Expected UUID',
        requestId,
        { field: 'depotId', value: body.depotId }
      ),
      400
    );
  }

  // Validate fleetId if provided
  if (body.fleetId && !isValidUuid(body.fleetId)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        'Invalid fleetId format. Expected UUID',
        requestId,
        { field: 'fleetId', value: body.fleetId }
      ),
      400
    );
  }

  // Validate trainIds if provided
  if (body.trainIds) {
    for (const trainId of body.trainIds) {
      if (!isValidUuid(trainId)) {
        return c.json(
          error(
            ErrorCodes.VALIDATION_ERROR,
            'Invalid trainId format in trainIds array',
            requestId,
            { field: 'trainIds', invalidValue: trainId }
          ),
          400
        );
      }
    }
  }

  // Validate horizonWeeks
  const horizonWeeks = body.horizonWeeks ?? 12;
  if (horizonWeeks < 1 || horizonWeeks > 52) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        'horizonWeeks must be between 1 and 52',
        requestId,
        { field: 'horizonWeeks', value: horizonWeeks }
      ),
      400
    );
  }

  // Build job data
  const jobData: TacticalSchedulerJobData = {
    fleetId: body.fleetId,
    trainIds: body.trainIds,
    horizonWeeks,
    dryRun: body.dryRun ?? false,
  };

  // Add job to queue
  const { id: jobId } = await addJob(
    QUEUE_NAMES.TACTICAL_SCHEDULER,
    'tactical-schedule',
    jobData
  );

  return c.json(
    success(
      {
        jobId,
        status: 'QUEUED',
        horizonWeeks,
        dryRun: body.dryRun ?? false,
      },
      {
        timing: { durationMs: getRequestDuration(c) },
      }
    ),
    202
  );
});

/**
 * POST /optimizer/strategic-plan
 *
 * Trigger strategic planning for a 10-year horizon.
 * Uses genetic algorithm to optimize long-term PM scheduling
 * and resource allocation.
 */
optimizerRoutes.post('/optimizer/strategic-plan', async (c) => {
  const requestId = getRequestId(c);

  // Parse request body
  let body: StrategicPlanRequest;
  try {
    body = await c.req.json();
  } catch {
    body = {}; // Allow empty body for default parameters
  }

  // Validate fromBaselineId if provided
  if (body.fromBaselineId && !isValidUuid(body.fromBaselineId)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        'Invalid fromBaselineId format. Expected UUID',
        requestId,
        { field: 'fromBaselineId', value: body.fromBaselineId }
      ),
      400
    );
  }

  // Validate fleetId if provided
  if (body.fleetId && !isValidUuid(body.fleetId)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        'Invalid fleetId format. Expected UUID',
        requestId,
        { field: 'fleetId', value: body.fleetId }
      ),
      400
    );
  }

  // Validate horizonYears
  const horizonYears = body.horizonYears ?? 10;
  if (horizonYears < 1 || horizonYears > 15) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        'horizonYears must be between 1 and 15',
        requestId,
        { field: 'horizonYears', value: horizonYears }
      ),
      400
    );
  }

  // Validate GA parameters
  const populationSize = body.populationSize ?? 100;
  if (populationSize < 10 || populationSize > 1000) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        'populationSize must be between 10 and 1000',
        requestId,
        { field: 'populationSize', value: populationSize }
      ),
      400
    );
  }

  const generations = body.generations ?? 500;
  if (generations < 10 || generations > 5000) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        'generations must be between 10 and 5000',
        requestId,
        { field: 'generations', value: generations }
      ),
      400
    );
  }

  // Build job data
  const jobData: StrategicPlannerJobData = {
    fleetId: body.fleetId,
    horizonYears,
    populationSize,
    generations,
  };

  // Add job to queue
  const { id: jobId } = await addJob(
    QUEUE_NAMES.STRATEGIC_PLANNER,
    'strategic-plan',
    jobData
  );

  // Estimate completion time for strategic planning (much longer)
  const estimatedCompletionSeconds = Math.ceil(
    (populationSize * generations) / 100 + 60
  );

  return c.json(
    success(
      {
        jobId,
        status: 'QUEUED',
        horizonYears,
        populationSize,
        generations,
        estimatedCompletionSeconds,
      },
      {
        timing: { durationMs: getRequestDuration(c) },
      }
    ),
    202
  );
});

/**
 * GET /optimizer/queue-stats
 *
 * Get statistics for all optimizer queues.
 * Useful for monitoring and debugging.
 */
optimizerRoutes.get('/optimizer/queue-stats', async (c) => {
  const optimizerQueue = getQueue(QUEUE_NAMES.OPTIMIZER);
  const tacticalQueue = getQueue(QUEUE_NAMES.TACTICAL_SCHEDULER);
  const strategicQueue = getQueue(QUEUE_NAMES.STRATEGIC_PLANNER);

  const [optimizerStats, tacticalStats, strategicStats] = await Promise.all([
    Promise.all([
      optimizerQueue.getWaitingCount(),
      optimizerQueue.getActiveCount(),
      optimizerQueue.getCompletedCount(),
      optimizerQueue.getFailedCount(),
      optimizerQueue.getDelayedCount(),
    ]),
    Promise.all([
      tacticalQueue.getWaitingCount(),
      tacticalQueue.getActiveCount(),
      tacticalQueue.getCompletedCount(),
      tacticalQueue.getFailedCount(),
      tacticalQueue.getDelayedCount(),
    ]),
    Promise.all([
      strategicQueue.getWaitingCount(),
      strategicQueue.getActiveCount(),
      strategicQueue.getCompletedCount(),
      strategicQueue.getFailedCount(),
      strategicQueue.getDelayedCount(),
    ]),
  ]);

  return c.json(
    success({
      optimizer: {
        waiting: optimizerStats[0],
        active: optimizerStats[1],
        completed: optimizerStats[2],
        failed: optimizerStats[3],
        delayed: optimizerStats[4],
      },
      tacticalScheduler: {
        waiting: tacticalStats[0],
        active: tacticalStats[1],
        completed: tacticalStats[2],
        failed: tacticalStats[3],
        delayed: tacticalStats[4],
      },
      strategicPlanner: {
        waiting: strategicStats[0],
        active: strategicStats[1],
        completed: strategicStats[2],
        failed: strategicStats[3],
        delayed: strategicStats[4],
      },
    })
  );
});

